// Capture chat context ONCE and carry it in the data flow.
// Downstream nodes must read from $json, not from cross-node refs —
// cross-node refs break on the retry path.
const intentRaw = String($json.text ?? $json.output ?? '').toLowerCase().trim();
let intent = 'analysis';
if (intentRaw.includes('schema')) intent = 'schema';
else if (intentRaw.includes('delete')) intent = 'delete';

let chatInput = '';
let sessionId = '';
try {
  const mc = $('Manager Chat').first().json;
  chatInput = mc.chatInput ?? '';
  sessionId = mc.sessionId ?? 'anonymous';
} catch (e) {}

return [{ json: { intent, chatInput, sessionId, retryCount: 0, retryHint: 'none' } }];

// Static few-shot Golden Bucket.
// Curated trios fit comfortably in-prompt; a vector store adds
// latency and an embedding dependency for zero retrieval benefit
// at this scale. Swap to a vector store node if the bucket grows
// past what fits in the prompt budget.
const trios = [
  { q: 'Who are our top 10 customers by total spend?', sql: 'SELECT o.user_id, SUM(oi.sale_price) AS total_spend, COUNT(DISTINCT o.order_id) AS orders FROM `bigquery-public-data.thelook_ecommerce.orders` o JOIN `bigquery-public-data.thelook_ecommerce.order_items` oi ON o.order_id = oi.order_id GROUP BY o.user_id ORDER BY total_spend DESC LIMIT 10' },
  { q: 'What are the top selling products this month?', sql: 'SELECT p.name AS product_name, COUNT(oi.id) AS units_sold, SUM(oi.sale_price) AS revenue FROM `bigquery-public-data.thelook_ecommerce.order_items` oi JOIN `bigquery-public-data.thelook_ecommerce.products` p ON oi.product_id = p.id GROUP BY p.name ORDER BY units_sold DESC LIMIT 10' },
  { q: 'Compare revenue and return rates by state', sql: 'SELECT u.state, SUM(oi.sale_price) AS revenue, COUNT(DISTINCT o.order_id) AS orders, SAFE_DIVIDE(COUNTIF(oi.status = "Returned"), COUNT(oi.id)) AS return_rate FROM `bigquery-public-data.thelook_ecommerce.users` u JOIN `bigquery-public-data.thelook_ecommerce.orders` o ON u.id = o.user_id JOIN `bigquery-public-data.thelook_ecommerce.order_items` oi ON o.order_id = oi.order_id GROUP BY u.state ORDER BY revenue DESC' },
  { q: 'Monthly revenue trend for 2023', sql: 'SELECT DATE_TRUNC(DATE(o.created_at), MONTH) AS month, SUM(oi.sale_price) AS revenue FROM `bigquery-public-data.thelook_ecommerce.orders` o JOIN `bigquery-public-data.thelook_ecommerce.order_items` oi ON o.order_id = oi.order_id WHERE DATE(o.created_at) BETWEEN "2023-01-01" AND "2023-12-31" GROUP BY month ORDER BY month' },
  { q: 'Which distribution centers ship the most inventory?', sql: 'SELECT dc.name AS distribution_center, COUNT(ii.id) AS items FROM `bigquery-public-data.thelook_ecommerce.distribution_centers` dc JOIN `bigquery-public-data.thelook_ecommerce.products` p ON p.distribution_center_id = dc.id JOIN `bigquery-public-data.thelook_ecommerce.inventory_items` ii ON ii.product_id = p.id GROUP BY dc.name ORDER BY items DESC' }
];

const trioText = trios.map(t => `Q: ${t.q}\nSQL: ${t.sql}`).join('\n\n');

return [{ json: {
  chatInput: $json.chatInput ?? '',
  sessionId: $json.sessionId ?? 'anonymous',
  retryCount: $json.retryCount ?? 0,
  retryHint: $json.retryHint ?? 'none',
  goldenBucketTrios: trioText
} }];

// Defensive input read: LLM Chain output key varies by n8n version.
const input = $input.first().json;
const raw = input.text ?? input.output ?? input.response ?? input.sql ?? '';

if (!raw) {
  throw new Error('No SQL text found in input. Available keys: ' + Object.keys(input).join(', '));
}

// Strip markdown fences — the model adds them despite instructions.
const sql = String(raw).trim()
  .replace(/^```(sql)?\s*/i, '')
  .replace(/```\s*$/, '')
  .trim();

const errors = [];

if (sql.includes(';')) errors.push('semicolon found');
if (!/^\s*SELECT\b/i.test(sql)) errors.push('must start with SELECT');
if (/\b(INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|MERGE|TRUNCATE)\b/i.test(sql)) errors.push('DDL/DML forbidden');
if (/SELECT\s+\*|\.\s*\*/i.test(sql)) errors.push('wildcard projection forbidden');

const piiColumns = ['email', 'phone', 'street_address', 'postal_code'];
const projectionMatch = sql.match(/SELECT([\s\S]*?)FROM/i);
if (projectionMatch) {
  const projection = projectionMatch[1].toLowerCase();
  for (const col of piiColumns) {
    if (projection.includes(col)) errors.push(`PII column projected: ${col}`);
  }
}

const allowedTables = ['users', 'orders', 'order_items', 'products', 'distribution_centers', 'inventory_items', 'events'];
const tableRefs = [...sql.matchAll(/thelook_ecommerce\.(\w+)/gi)].map(m => m[1].toLowerCase());
for (const t of tableRefs) {
  if (!allowedTables.includes(t)) errors.push(`table not allow-listed: ${t}`);
}

// Carry context forward in the data flow.
let chatInput = '';
let sessionId = 'anonymous';
let retryCount = 0;
try {
  const gb = $('Golden Bucket').first().json;
  chatInput = gb.chatInput ?? '';
  sessionId = gb.sessionId ?? 'anonymous';
  retryCount = gb.retryCount ?? 0;
} catch (e) {}

return [{ json: { sql, valid: errors.length === 0, errors, chatInput, sessionId, retryCount } }];

// Merge BigQuery rows with carried context. BigQuery output does not
// include our context fields, so re-attach them from SQL Validator
// (same execution path, but keep the guard anyway).
let ctx = { chatInput: '', sessionId: 'anonymous', retryCount: 0, sql: '' };
try {
  const v = $('SQL Validator').first().json;
  ctx = { chatInput: v.chatInput ?? '', sessionId: v.sessionId ?? 'anonymous', retryCount: v.retryCount ?? 0, sql: v.sql ?? '' };
} catch (e) {}

return $input.all().map(i => ({ json: { ...i.json, ...ctx } }));

// Self-heal: on execution error or empty result, loop back with a hint.
// All context comes from the data flow — no fragile cross-node refs
// on the error path.
const items = $input.all();

const first = items[0]?.json ?? {};
const retryCount = first.retryCount ?? 0;
const chatInput = first.chatInput ?? '';
const sessionId = first.sessionId ?? 'anonymous';

let trios = '';
try { trios = $('Golden Bucket').first().json.goldenBucketTrios ?? ''; } catch (e) {}

const hasError = items.some(i => i.json.error !== undefined || i.json.valid === false);
const dataKeys = items.length ? Object.keys(first).filter(k => !['chatInput','sessionId','retryCount','sql','valid','errors','error'].includes(k)) : [];
const isEmpty = items.length === 0 || dataKeys.length === 0;

if ((hasError || isEmpty) && retryCount < 2) {
  const firstErr = first.errors?.join('; ') ?? (first.error?.message ?? first.error) ?? 'query returned no rows — check date ranges (data spans 2019-2024)';
  return [{ json: {
    needsRetry: true,
    retryCount: retryCount + 1,
    retryHint: String(firstErr),
    chatInput,
    sessionId,
    goldenBucketTrios: trios
  } }];
}

return items.map(i => ({
  json: { ...i.json, needsRetry: false, exhausted: (hasError || isEmpty) }
}));

// Deterministic PII masking — regex, not LLM-based, so it cannot be
// prompt-injected out of masking.
const PII_PATTERNS = [
  { re: /[\w.+-]+@[\w-]+\.[\w.]+/g, mask: '[EMAIL_REDACTED]' },
  { re: /\+?\d[\d\s().-]{7,}\d/g, mask: '[PHONE_REDACTED]' },
  { re: /\d{1,5}\s+\w+\s+(street|st|avenue|ave|road|rd|blvd)\b/gi, mask: '[ADDRESS_REDACTED]' }
];
const PII_COLUMNS = ['email', 'phone', 'street_address', 'postal_code'];

return $input.all().map(item => {
  const masked = {};
  for (const [key, val] of Object.entries(item.json)) {
    if (PII_COLUMNS.includes(key.toLowerCase())) { masked[key] = '[REDACTED]'; continue; }
    let v = val;
    if (typeof v === 'string') for (const p of PII_PATTERNS) v = v.replace(p.re, p.mask);
    masked[key] = v;
  }
  return { json: masked };
});

let exhausted = false;
try { exhausted = $('Self-Healer').first().json.exhausted ?? false; } catch (e) {}

return [{ json: {
  event: 'turn_summary',
  turn_id: $execution.id,
  outcome: exhausted ? 'graceful_failure' : 'ok',
  report_id: $json.id ?? null,
  timestamp: new Date().toISOString()
} }];

// Preview + collect matched ids for the scoped delete after confirmation.
const items = $input.all();
const ids = items.map(i => i.json.id).filter(id => id !== undefined);

let sessionId = 'anonymous';
try { sessionId = $('Carry Context').first().json.sessionId ?? 'anonymous'; } catch (e) {}

const preview = items.map(i => `#${i.json.id}: ${i.json.question} (${i.json.created_at})`).join('\n') || 'No matching reports.';

return [{ json: {
  matchedIds: ids,
  sessionId,
  message: `Matched ${ids.length} owner-scoped report(s). Preview:\n${preview}\n\nType exactly CONFIRM DELETE to delete. Any other reply cancels. Expires in 10 minutes.`
} }];
